#include <stdio.h>
#include <stdlib.h>
typedef struct Node {
    int data;
    struct Node* next;
} Node;
typedef struct Queue {
    Node* front;
    Node* rear;
} Queue;
void initQueue(Queue* q) {
    q->front = NULL;
    q->rear = NULL;
}
void enqueue(Queue* q, int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->data = data;
    newNode->next = NULL;
    if (q->rear == NULL) {
        q->front = newNode;
        q->rear = newNode;
    } else {
        q->rear->next = newNode;
        q->rear = newNode;
    }
}
int dequeue(Queue* q) {
    if (q->front == NULL) {
        return -1;
    }
    int data = q->front->data;
    Node* temp = q->front;
    q->front = q->front->next;
    free(temp);
    if (q->front == NULL) {
        q->rear = NULL;
    }
    return data;
}
int isEmpty(Queue* q) {
    return q->front == NULL;
}
typedef struct Stack {
    Queue q;
} Stack;
void initStack(Stack* s) {
    initQueue(&s->q);
}
void push(Stack* s, int data) {
    enqueue(&s->q, data);
    for (int i = 0; i < size(&s->q) - 1; i++) {
        enqueue(&s->q, dequeue(&s->q));
    }
}
int pop(Stack* s) {
    return dequeue(&s->q);
}
int top(Stack* s) {
    return s->q.front->data;
}
int size(Queue* q) {
    int count = 0;
    Node* temp = q->front;
    while (temp != NULL) {
        count++;
        temp = temp->next;
    }
    return count;
}
int main() {
    Stack s;
    initStack(&s);
    // Test the stack
    push(&s, 1);
    push(&s, 2);
    printf("%d\n", pop(&s)); // Output: 2
    printf("%d\n", top(&s)); // Output: 1
    return 0;
}

